trait SafeCounter {
    fn count(&self) -> usize;
}

struct Counter {
    value: usize,
}

impl SafeCounter for Counter {
    fn count(&self) -> usize {
        self.value + unsafe { recursive_increment(self.value, 100000) }
    }
}

unsafe fn recursive_increment(n: usize, max: usize) -> usize {
    if n >= max {
        n
    } else {
        recursive_increment(n + 1, max)
    }
}

fn main() {
    let c = Counter { value: 50000 };
    println!("Count is: {}", c.count());
}

