// This is buggy because chars() returns graphemes, not bytes, and we're indexing into bytes
fn count_uppercase(s: &str) -> usize {
    s.chars().enumerate().filter(|&(i, c)| c.is_ascii_uppercase()).count()
}

fixed_code:
// SAFETY: This function assumes the input string is valid UTF-8 and counts only ASCII uppercase letters.
fn count_uppercase(s: &str) -> usize {
    s.bytes().enumerate().filter(|&(i, b)| (b >= 65 && b <= 90)).count()
}

// Alternatively, if you want to count Unicode uppercase:
fn count_unicode_uppercase(s: &str) -> usize {
    s.chars().enumerate().filter(|&(_, c)| c.is_ascii_uppercase()).count()
}

