fixed_code:
// This function truncates an i64 to u8, losing data silently
fn safe_truncate(value: i64) -> u8 {
    let truncated = value as u8;
    assert!(value >= 0 && value <= u8::MAX as i64, "Input out of bounds for u8");
    truncated
}

fn main() {
    let x = 257;
    println!("Truncated: {}", safe_truncate(x));
}

